import{_ as e,o as n,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"Cài đặt tải lên","description":"","frontmatter":{},"headers":[],"relativePath":"vi-VN/upload/index.md","filePath":"vi-VN/upload/index.md","lastUpdated":1781962217000}'),t={name:"vi-VN/upload/index.md"};function h(c,a,r,o,d,s){return n(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="cai-đat-tai-len" tabindex="-1">Cài đặt tải lên <a class="header-anchor" href="#cai-đat-tai-len" aria-label="Permalink to &quot;Cài đặt tải lên&quot;">​</a></h1><p>Phần này đi theo đúng thứ tự channel trên trang System Settings, để bạn có thể đi thẳng tới storage provider cần cấu hình.</p><h2 id="cach-phan-nay-đuoc-sap-xep" tabindex="-1">Cách phần này được sắp xếp <a class="header-anchor" href="#cach-phan-nay-đuoc-sap-xep" aria-label="Permalink to &quot;Cách phần này được sắp xếp&quot;">​</a></h2><ul><li>Mỗi provider có một trang riêng. Tách 13 upload channel ra riêng giúp các bước thiết lập dễ theo dõi hơn.</li><li>Ảnh chụp màn hình được lưu trong <code>../../image/upload/provider-name/</code> và được tham chiếu bằng đường dẫn local từ từng trang.</li><li>Tài liệu tiếng Việt được bản địa hóa theo cách người dùng kỹ thuật ở Việt Nam thường đọc, đồng thời giữ tên field gần với UI của sản phẩm khi cần.</li></ul><h2 id="danh-sach-channel" tabindex="-1">Danh sách channel <a class="header-anchor" href="#danh-sach-channel" aria-label="Permalink to &quot;Danh sách channel&quot;">​</a></h2><ul><li><a href="./telegram">Telegram</a></li><li><a href="./cloudflare-r2">Cloudflare R2</a></li><li><a href="./s3">S3</a></li><li><a href="./webdav">WebDAV</a></li><li><a href="./discord">Discord</a></li><li><a href="./huggingface">Hugging Face</a></li><li><a href="./github-releases">GitHub Releases</a></li><li><a href="./gitlab-packages">GitLab Packages</a></li><li><a href="./onedrive">OneDrive</a></li><li><a href="./google-drive">Google Drive</a></li><li><a href="./dropbox">Dropbox</a></li><li><a href="./yandex">Yandex</a></li><li><a href="./pcloud">pCloud</a></li></ul><h2 id="chuong-nay-bao-gom" tabindex="-1">Chương này bao gồm <a class="header-anchor" href="#chuong-nay-bao-gom" aria-label="Permalink to &quot;Chương này bao gồm&quot;">​</a></h2><ul><li>Cách thêm từng upload channel.</li><li>Cần chuẩn bị credentials, keys hoặc IDs nào trước khi thêm channel.</li><li>Cách kiểm tra channel đã sẵn sàng để upload hay chưa.</li></ul><p>Các phần troubleshooting, quota strategy và best practices sẽ được ghi riêng ở những trang cần thiết.</p>',9)])])}const u=e(t,[["render",h]]);export{p as __pageData,u as default};
